  1→/**
  2→ * Agent Management Acceptance Test Kit
  3→ *
  4→ * Extends the shared acceptance-test-kit with agent-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   GET    /api/workspaces/:workspaceId/agents          (list agents)
  9→ *   POST   /api/workspaces/:workspaceId/agents          (create agent)
 10→ *   GET    /api/workspaces/:workspaceId/agents/:agentId (agent detail)
 11→ *   PUT    /api/workspaces/:workspaceId/agents/:agentId (update agent)
 12→ *   DELETE /api/workspaces/:workspaceId/agents/:agentId (delete agent)
 13→ *   SurrealDB direct queries                            (verification of outcomes)
 14→ */
 15→import { RecordId, type Surreal } from "surrealdb";
 16→import {
 17→  createWorkspaceDirectly,
 18→  createWorkspaceViaHttp,
 19→  type DirectWorkspaceResult,
 20→} from "../shared-fixtures";
 21→
 22→// ---------------------------------------------------------------------------
 23→// Re-exports from shared kit
 24→// ---------------------------------------------------------------------------
 25→
 26→export {
 27→  setupAcceptanceSuite,
 28→  createTestUser,
 29→  createTestUserWithMcp,
 30→  fetchJson,
 31→  fetchRaw,
 32→  type AcceptanceTestRuntime,
 33→  type TestUser,
 34→  type TestUserWithMcp,
 35→} from "../acceptance-test-kit";
 36→
 37→import {
 38→  setupAcceptanceSuite,
 39→  fetchRaw,
 40→  type AcceptanceTestRuntime,
 41→  type TestUser,
 42→} from "../acceptance-test-kit";
 43→
 44→// ---------------------------------------------------------------------------
 45→// Agent Domain Types
 46→// ---------------------------------------------------------------------------
 47→
 48→export type AgentRuntime = "brain" | "sandbox" | "external";
 49→
 50→export type AuthorityScopeInput = {
 51→  action: string;
 52→  permission: "auto" | "propose" | "blocked";
 53→};
 54→
 55→export type SandboxConfig = {
 56→  coding_agents?: string[];
 57→  env_vars?: { key: string; value: string }[];
 58→  image?: string;
 59→  snapshot?: string;
 60→  model?: string;
 61→};
 62→
 63→export type CreateAgentInput = {
 64→  name: string;
 65→  description?: string;
 66→  runtime: "sandbox" | "external";
 67→  model?: string;
 68→  sandbox_config?: SandboxConfig;
 69→  authority_scopes?: AuthorityScopeInput[];
 70→};
 71→
 72→export type AgentListItem = {
 73→  id: string;
 74→  name: string;
 75→  description?: string;
 76→  runtime: AgentRuntime;
 77→  model?: string;
 78→  identity_id: string;
 79→  created_at: string;
 80→};
 81→
 82→export type AgentDetailResponse = {
 83→  agent: AgentListItem & { sandbox_config?: SandboxConfig };
 84→  identity: { id: string; name: string; type: string; role?: string };
 85→  authority_scopes: { action: string; permission: string }[];
 86→  sessions: Array<{
 87→    id: string;
 88→    started_at: string;
 89→    ended_at?: string;
 90→    orchestrator_status?: string;
 91→    summary?: string;
 92→  }>;
 93→};
 94→
 95→export type CreateAgentResponse = {
 96→  agent: AgentListItem;
 97→  proxy_token?: string;
 98→};
 99→
100→export type DeleteAgentResponse = {
101→  deleted: true;
102→  sessions_aborted: number;
103→};
104→
105→// ---------------------------------------------------------------------------
106→// Suite Setup
107→// ---------------------------------------------------------------------------
108→
109→/**
110→ * Sets up an agent acceptance test suite with an isolated server + DB.
111→ */
112→export function setupAgentSuite(
113→  suiteName: string,
114→): () => AcceptanceTestRuntime {
115→  return setupAcceptanceSuite(suiteName);
116→}
117→
118→// ---------------------------------------------------------------------------
119→// Domain Helpers -- Business Language Layer
120→// ---------------------------------------------------------------------------
121→
122→/**
123→ * Creates a workspace with a session-authenticated user.
124→ * Use when tests exercise browser-facing routes that validate workspace
125→ * membership through the Better Auth session.
126→ */
127→export async function createAgentTestWorkspace(
128→  baseUrl: string,
129→  surreal: Surreal,
130→  suffix: string,
131→): Promise<{
132→  user: TestUser;
133→  workspaceId: string;
134→}> {
135→  const { createTestUser } = await import("../acceptance-test-kit");
136→  const user = await createTestUser(baseUrl, `agent-${suffix}-${crypto.randomUUID()}`);
137→  const { workspaceId } = await createWorkspaceViaHttp(baseUrl, user, surreal);
138→  return { user, workspaceId };
139→}
140→
141→/**
142→ * Creates a workspace directly in SurrealDB (no HTTP, no session auth).
143→ * Use for tests that only need data in the DB without going through HTTP signup.
144→ */
145→export async function createAgentTestWorkspaceDirect(
146→  surreal: Surreal,
147→  suffix: string,
148→): Promise<DirectWorkspaceResult> {
149→  return createWorkspaceDirectly(surreal, suffix, {
150→    workspaceName: `Agent Test Workspace ${suffix}`,
151→  });
152→}
153→
154→// ---------------------------------------------------------------------------
155→// HTTP Helpers -- Driving Port Invocations
156→// ---------------------------------------------------------------------------
157→
158→/**
159→ * Lists all agents in a workspace via the HTTP endpoint.
160→ */
161→export async function listAgentsViaHttp(
162→  baseUrl: string,
163→  user: TestUser,
164→  workspaceId: string,
165→): Promise<Response> {
166→  return fetchRaw(
167→    `${baseUrl}/api/workspaces/${workspaceId}/agents`,
168→    {
169→      method: "GET",
170→      headers: user.headers,
171→    },
172→  );
173→}
174→
175→/**
176→ * Creates an agent via the HTTP endpoint.
177→ */
178→export async function createAgentViaHttp(
179→  baseUrl: string,
180→  user: TestUser,
181→  workspaceId: string,
182→  input: CreateAgentInput,
183→): Promise<Response> {
184→  return fetchRaw(
185→    `${baseUrl}/api/workspaces/${workspaceId}/agents`,
186→    {
187→      method: "POST",
188→      headers: { "Content-Type": "application/json", ...user.headers },
189→      body: JSON.stringify(input),
190→    },
191→  );
192→}
193→
194→/**
195→ * Gets agent detail via the HTTP endpoint.
196→ */
197→export async function getAgentDetailViaHttp(
198→  baseUrl: string,
199→  user: TestUser,
200→  workspaceId: string,
201→  agentId: string,
202→): Promise<Response> {
203→  return fetchRaw(
204→    `${baseUrl}/api/workspaces/${workspaceId}/agents/${agentId}`,
205→    {
206→      method: "GET",
207→      headers: user.headers,
208→    },
209→  );
210→}
211→
212→/**
213→ * Updates an agent via the HTTP endpoint.
214→ */
215→export async function updateAgentViaHttp(
216→  baseUrl: string,
217→  user: TestUser,
218→  workspaceId: string,
219→  agentId: string,
220→  input: Partial<CreateAgentInput>,
221→): Promise<Response> {
222→  return fetchRaw(
223→    `${baseUrl}/api/workspaces/${workspaceId}/agents/${agentId}`,
224→    {
225→      method: "PUT",
226→      headers: { "Content-Type": "application/json", ...user.headers },
227→      body: JSON.stringify(input),
228→    },
229→  );
230→}
231→
232→/**
233→ * Deletes an agent via the HTTP endpoint.
234→ */
235→export async function deleteAgentViaHttp(
236→  baseUrl: string,
237→  user: TestUser,
238→  workspaceId: string,
239→  agentId: string,
240→  confirmName: string,
241→): Promise<Response> {
242→  return fetchRaw(
243→    `${baseUrl}/api/workspaces/${workspaceId}/agents/${agentId}`,
244→    {
245→      method: "DELETE",
246→      headers: { "Content-Type": "application/json", ...user.headers },
247→      body: JSON.stringify({ confirm_name: confirmName }),
248→    },
249→  );
250→}
251→
252→// ---------------------------------------------------------------------------
253→// Verification Helpers -- Direct DB Queries for Then-Step Assertions
254→// ---------------------------------------------------------------------------
255→
256→/**
257→ * Queries the agent record directly from SurrealDB.
258→ */
259→export async function getAgentFromDb(
260→  surreal: Surreal,
261→  agentId: string,
262→): Promise<Record<string, unknown> | undefined> {
263→  const agentRecord = new RecordId("agent", agentId);
264→  const rows = (await surreal.query(
265→    `SELECT * FROM $agent;`,
266→    { agent: agentRecord },
267→  )) as Array<Array<Record<string, unknown>>>;
268→  return rows[0]?.[0];
269→}
270→
271→/**
272→ * Queries the identity record linked to an agent via identity_agent edge.
273→ */
274→export async function getIdentityForAgent(
275→  surreal: Surreal,
276→  agentId: string,
277→): Promise<Record<string, unknown> | undefined> {
278→  const agentRecord = new RecordId("agent", agentId);
279→  const rows = (await surreal.query(
280→    `SELECT VALUE in FROM identity_agent WHERE out = $agent LIMIT 1;`,
281→    { agent: agentRecord },
282→  )) as Array<Array<RecordId>>;
283→  const identityRecord = rows[0]?.[0];
284→  if (!identityRecord) return undefined;
285→
286→  const identityRows = (await surreal.query(
287→    `SELECT * FROM $identity;`,
288→    { identity: identityRecord },
289→  )) as Array<Array<Record<string, unknown>>>;
290→  return identityRows[0]?.[0];
291→}
292→
293→/**
294→ * Queries authorized_to edges for an identity.
295→ */
296→export async function getAuthorityEdgesForIdentity(
297→  surreal: Surreal,
298→  identityId: string,
299→): Promise<Array<{ action: string; permission: string }>> {
300→  const identityRecord = new RecordId("identity", identityId);
301→  const rows = (await surreal.query(
302→    `SELECT out.action AS action, permission FROM authorized_to WHERE in = $identity;`,
303→    { identity: identityRecord },
304→  )) as Array<Array<{ action: string; permission: string }>>;
305→  return rows[0] ?? [];
306→}
307→
308→/**
309→ * Queries the member_of edge between an identity and workspace.
310→ */
311→export async function hasMemberOfEdge(
312→  surreal: Surreal,
313→  identityId: string,
314→  workspaceId: string,
315→): Promise<boolean> {
316→  const identityRecord = new RecordId("identity", identityId);
317→  const workspaceRecord = new RecordId("workspace", workspaceId);
318→  const rows = (await surreal.query(
319→    `SELECT id FROM member_of WHERE in = $identity AND out = $ws;`,
320→    { identity: identityRecord, ws: workspaceRecord },
321→  )) as Array<Array<{ id: RecordId }>>;
322→  return (rows[0]?.length ?? 0) > 0;
323→}
324→
325→/**
326→ * Queries proxy_token records for an identity.
327→ */
328→export async function getProxyTokensForIdentity(
329→  surreal: Surreal,
330→  identityId: string,
331→): Promise<Array<Record<string, unknown>>> {
332→  const identityRecord = new RecordId("identity", identityId);
333→  const rows = (await surreal.query(
334→    `SELECT * FROM proxy_token WHERE identity = $identity;`,
335→    { identity: identityRecord },
336→  )) as Array<Array<Record<string, unknown>>>;
337→  return rows[0] ?? [];
338→}
339→
340→/**
341→ * Checks whether an agent record exists in the database.
342→ */
343→export async function agentExistsInDb(
344→  surreal: Surreal,
345→  agentId: string,
346→): Promise<boolean> {
347→  const agent = await getAgentFromDb(surreal, agentId);
348→  return agent !== undefined;
349→}
350→
351→/**
352→ * Checks whether an identity record exists in the database.
353→ */
354→export async function identityExistsInDb(
355→  surreal: Surreal,
356→  identityId: string,
357→): Promise<boolean> {
358→  const identityRecord = new RecordId("identity", identityId);
359→  const rows = (await surreal.query(
360→    `SELECT id FROM $identity;`,
361→    { identity: identityRecord },
362→  )) as Array<Array<{ id: RecordId }>>;
363→  return (rows[0]?.length ?? 0) > 0;
364→}
365→
366→/**
367→ * Creates a brain agent directly in SurrealDB (for seeding test state).
368→ * Mirrors the identity bootstrap that creates system agents.
369→ * Writes both `runtime` and `agent_type` fields — this matches the parallel-write
370→ * migration strategy (ADR-081) where both fields coexist during the transition period.
371→ */
372→export async function seedBrainAgent(
373→  surreal: Surreal,
374→  workspaceId: string,
375→  name: string,
376→  opts?: { description?: string; agentType?: string },
377→): Promise<{ agentId: string; identityId: string }> {
378→  const agentId = crypto.randomUUID();
379→  const identityId = crypto.randomUUID();
380→  const agentRecord = new RecordId("agent", agentId);
381→  const identityRecord = new RecordId("identity", identityId);
382→  const workspaceRecord = new RecordId("workspace", workspaceId);
383→
384→  await surreal.query(`CREATE $agent CONTENT $content;`, {
385→    agent: agentRecord,
386→    content: {
387→      name,
388→      runtime: "brain",
389→      agent_type: opts?.agentType ?? "chat_agent",
390→      description: opts?.description ?? `Brain agent: ${name}`,
391→      managed_by: identityRecord,
392→      created_at: new Date(),
393→    },
394→  });
395→
396→  await surreal.query(`CREATE $identity CONTENT $content;`, {
397→    identity: identityRecord,
398→    content: {
399→      name,
400→      type: "agent",
401→      role: opts?.agentType ?? "chat_agent",
402→      identity_status: "active",
403→      workspace: workspaceRecord,
404→      created_at: new Date(),
405→    },
406→  });
407→
408→  await surreal.query(
409→    `RELATE $identity->identity_agent->$agent SET added_at = time::now();`,
410→    { identity: identityRecord, agent: agentRecord },
411→  );
412→
413→  await surreal.query(
414→    `RELATE $identity->member_of->$workspace SET added_at = time::now(), role = "agent";`,
415→    { identity: identityRecord, workspace: workspaceRecord },
416→  );
417→
418→  return { agentId, identityId };
419→}
