export async function resolveWorkspaceRecord(
  surreal: Surreal,
  workspaceId: string,
): Promise<RecordId<"workspace", string>> {
  const [rows] = await surreal.query<[Array<{ id: RecordId<"workspace", string> }>]>(
    "SELECT id FROM workspace WHERE id = $id LIMIT 1;",
    { id: workspaceId },
  );

  if (rows.length === 0) {
    throw new HttpError(404, "workspace not found");
  }

  return rows[0].id;
}
