{
  "roadmap": {
    "project_id": "agent-creation",
    "created_at": "2026-03-28T15:50:38Z",
    "total_steps": 15,
    "phases": 6
  },
  "phases": [
    {
      "id": "01",
      "name": "Schema and Backend Foundation",
      "steps": [
        {
          "id": "01-01",
          "name": "Schema migration: agent runtime, name, and sandbox_config fields",
          "criteria": "Migration 0081 adds runtime, name, sandbox_config to agent table. Backfills runtime from agent_type. identity-bootstrap.ts writes runtime:'brain' for system agents. bun migrate applies cleanly.",
          "test_file": "",
          "scenario_name": ""
        },
        {
          "id": "01-02",
          "name": "Schema migration: workspace sandbox provider setting",
          "criteria": "Migration 0082 adds settings.sandbox_provider to workspace table. bun migrate applies cleanly.",
          "test_file": "",
          "scenario_name": ""
        },
        {
          "id": "01-03",
          "name": "Agent domain types and query functions",
          "criteria": "agents/types.ts exports domain types including AuthorityAction (11 actions). agents/queries.ts exports graph traversal, creation transaction, and deletion transaction functions.",
          "test_file": "",
          "scenario_name": ""
        },
        {
          "id": "01-04",
          "name": "Agent CRUD route handlers and registration",
          "criteria": "agents/routes.ts exports handlers for list, create, detail, check-name, delete. Routes registered in start-server.ts with Better Auth session auth and withTracing.",
          "test_file": "",
          "scenario_name": ""
        }
      ]
    },
    {
      "id": "02",
      "name": "API Integration and Transaction Wiring",
      "steps": [
        {
          "id": "02-01",
          "name": "Atomic creation transaction with proxy token generation",
          "criteria": "POST /agents creates agent+identity+edges+scopes+token in one transaction. 11 actions default to propose. brp_ token returned for external agents. Rollback on failure.",
          "test_file": "tests/acceptance/agents/external-agent-crud.test.ts",
          "scenario_name": "EC-3"
        },
        {
          "id": "02-02",
          "name": "Atomic deletion transaction with edge cleanup",
          "criteria": "DELETE /agents/:id validates confirm_name, removes all edges+identity+agent atomically. Brain agents rejected with 403. Session abort logic deferred to R2.",
          "test_file": "tests/acceptance/agents/external-agent-crud.test.ts",
          "scenario_name": "EC-16"
        },
        {
          "id": "02-03",
          "name": "Agent list, detail, and check-name endpoints",
          "criteria": "GET /agents returns workspace agents via single-query graph traversal. GET /agents/:id returns detail with authority scopes. GET /agents/check-name returns { available: boolean }. Workspace isolation enforced.",
          "test_file": "tests/acceptance/agents/walking-skeleton.test.ts",
          "scenario_name": "WS-4"
        }
      ]
    },
    {
      "id": "03",
      "name": "Backend Acceptance Tests",
      "steps": [
        {
          "id": "03-01",
          "name": "Walking skeleton acceptance tests",
          "criteria": "walking-skeleton.test.ts passes all 4 scenarios: register external agent, view detail with scopes, delete with cleanup, list agents by runtime.",
          "test_file": "tests/acceptance/agents/walking-skeleton.test.ts",
          "scenario_name": "WS-1, WS-2, WS-3, WS-4"
        },
        {
          "id": "03-02",
          "name": "External agent CRUD focused acceptance tests",
          "criteria": "external-agent-crud.test.ts passes all 19 scenarios covering happy paths, error paths, and workspace isolation boundaries.",
          "test_file": "tests/acceptance/agents/external-agent-crud.test.ts",
          "scenario_name": "EC-1 through EC-19"
        }
      ]
    },
    {
      "id": "04",
      "name": "Frontend: Agent Registry and Detail Pages",
      "steps": [
        {
          "id": "04-01",
          "name": "Agents page route, nav link, and agent card component",
          "criteria": "agents-page.tsx renders agent list grouped by runtime (brain/sandbox/external). agent-card.tsx shows name, description, runtime badge, and runtime-appropriate actions. Route registered in router.tsx at /agents. Nav link added to WorkspaceSidebar.",
          "test_file": "",
          "scenario_name": ""
        },
        {
          "id": "04-02",
          "name": "Agent detail page with authority scopes display",
          "criteria": "agent-detail-page.tsx renders agent config, authority scopes as action-permission pairs, and recent sessions. Route registered at /agents/$agentId. Back navigation returns to registry. Brain agents show read-only note.",
          "test_file": "",
          "scenario_name": ""
        }
      ]
    },
    {
      "id": "05",
      "name": "Frontend: Creation Flow and Confirmation",
      "steps": [
        {
          "id": "05-01",
          "name": "External agent creation form with authority scope configuration",
          "criteria": "agent-create-page.tsx renders runtime selection then creation form. authority-scope-form.tsx renders 11 actions with permission dropdowns (auto/propose/blocked). Name field validates uniqueness via check-name endpoint. Create button posts to API.",
          "test_file": "",
          "scenario_name": ""
        },
        {
          "id": "05-02",
          "name": "Proxy token dialog and delete confirmation",
          "criteria": "proxy-token-dialog.tsx shows brp_ token once with copy button and connection instructions. Delete confirmation requires typing agent name. Empty states show create guidance per runtime section.",
          "test_file": "",
          "scenario_name": ""
        }
      ]
    },
    {
      "id": "06",
      "name": "Frontend Component Tests",
      "steps": [
        {
          "id": "06-01",
          "name": "Agent registry and card component tests",
          "criteria": "agents-page.test.tsx verifies runtime grouping, brain View-only, external Edit action, empty state guidance, agent count header. agent-card.test.tsx verifies runtime badge and action buttons.",
          "test_file": "app/src/client/routes/agents-page.test.tsx",
          "scenario_name": ""
        },
        {
          "id": "06-02",
          "name": "Creation form, authority scope, and dialog tests",
          "criteria": "agent-create-page.test.tsx verifies runtime selection, form fields, name uniqueness API call, submit payload. authority-scope-form.test.tsx verifies 11 actions with propose defaults. proxy-token-dialog.test.tsx verifies token display and copy.",
          "test_file": "app/src/client/routes/agent-create-page.test.tsx",
          "scenario_name": ""
        }
      ]
    }
  ],
  "implementation_scope": {
    "source_directories": [
      "app/src/server/agents/",
      "app/src/server/runtime/start-server.ts",
      "app/src/server/workspace/identity-bootstrap.ts",
      "schema/migrations/",
      "app/src/client/routes/",
      "app/src/client/components/agent/",
      "app/src/client/router.tsx",
      "app/src/client/components/layout/WorkspaceSidebar.tsx"
    ],
    "test_directories": [
      "tests/acceptance/agents/",
      "app/src/client/routes/",
      "app/src/client/components/agent/"
    ],
    "excluded_patterns": [
      "docs/**"
    ]
  },
  "validation": {
    "status": "pending",
    "reviewer": "solution-architect-reviewer",
    "approved_at": ""
  }
}

